using NUnit.Framework;

namespace Azure.ResourceManager.ConfidentialLedger.Samples
{
    public class Sample_ConfidentialLedger
    {
        [Test]
        [Ignore("Only validating compilation of examples")]
        public async Task CreateOrUpdate_Sample()
        {
            #region Snippet:ConfidentialLedger_CreateOrUpdate
            TokenCredential cred = new DefaultAzureCredential();
            ArmClient client = new ArmClient(cred);

            string subscriptionId = "0000000-0000-0000-0000-000000000001";
            string resourceGroupName = "DummyResourceGroupName";
            string ledgerName = "DummyLedgerName";

            ResourceIdentifier resourceGroupId = ResourceGroupResource.CreateResourceIdentifier(subscriptionId, resourceGroupName);
            ResourceGroupResource resourceGroup = client.GetResourceGroupResource(resourceGroupId);

            ConfidentialLedgerCollection ledgers = resourceGroup.GetConfidentialLedgers();

            ConfidentialLedgerData data = new ConfidentialLedgerData(AzureLocation.EastUS)
            {
                Properties = new ConfidentialLedgerProperties
                {
                    LedgerType = ConfidentialLedgerType.Public,
                    LedgerSku = ConfidentialLedgerSku.Standard,
                },
            };

            ArmOperation<ConfidentialLedgerResource> lro = await ledgers.CreateOrUpdateAsync(WaitUntil.Completed, ledgerName, data);
            ConfidentialLedgerResource ledger = lro.Value;

            Console.WriteLine($"Succeeded on id: {ledger.Data.Id}");
            #endregion
        }

        [Test]
        [Ignore("Only validating compilation of examples")]
        public async Task Get_Sample()
        {
