            #endregion
        }

        [Test]
        [Ignore("Only validating compilation of examples")]
        public async Task FilesExport_Sample()
        {
            #region Snippet:ConfidentialLedger_FilesExport
            TokenCredential cred = new DefaultAzureCredential();
            ArmClient client = new ArmClient(cred);

            string subscriptionId = "0000000-0000-0000-0000-000000000001";
            string resourceGroupName = "DummyResourceGroupName";
            string ledgerName = "DummyLedgerName";

            ResourceIdentifier ledgerId = ConfidentialLedgerResource.CreateResourceIdentifier(subscriptionId, resourceGroupName, ledgerName);
            ConfidentialLedgerResource ledger = client.GetConfidentialLedgerResource(ledgerId);

            ConfidentialLedgerFilesExportContent content = new ConfidentialLedgerFilesExportContent
            {
